  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasUnits ?child ; p:hasApartment_Buildings ?parent . } GROUP BY ?child }
  ?child p:unit_type ?unit_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Apartment_Buildings } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?unit_type WHERE {
